UPDATE questionnaire
SET questionnaire_code = #{questionnaireCode},
    title = #{title},
    description = #{description},
    disease_scope = #{diseaseScope},
    status = #{status},
    version_no = #{versionNo},
    validated_flag = #{validatedFlag}
